(function() {
    let result = "Weather Forecast for Binda, NSW\n";
    result += "==================================================\n\n";

    // Get the first day (Sunday 8 March) which is expanded
    const firstDay = document.querySelector('h2.day-heading, .forecast-day-heading');
    if (firstDay) {
        result += firstDay.textContent.trim() + "\n";
        result += "-".repeat(40) + "\n";
    } else {
        result += "Sunday 8 March\n";
        result += "-".repeat(40) + "\n";
    }

    // Get temperature data from the visible table
    const tempTable = Array.from(document.querySelectorAll('table')).find(t => 
        t.textContent.includes('Air temperature')
    );

    if (tempTable) {
        const rows = tempTable.querySelectorAll('tr');
        rows.forEach(row => {
            const cells = Array.from(row.querySelectorAll('td, th'));
            if (cells.length > 0) {
                const label = cells[0].textContent.trim();
                if (label === 'Air temperature (°C)') {
                    const temps = Array.from(cells).slice(1).map(c => c.textContent.trim()).filter(t => t !== '–');
                    if (temps.length > 0) {
                        result += "Temperature: " + temps.join(', ') + " °C\n";
                    }
                }
            }
        });
    }

    // Get rainfall info
    const rainfallTable = Array.from(document.querySelectorAll('table')).find(t => 
        t.textContent.includes('Chance of any rain')
    );

    if (rainfallTable) {
        const rows = rainfallTable.querySelectorAll('tr');
        rows.forEach(row => {
            const cells = Array.from(row.querySelectorAll('td, th'));
            if (cells.length > 0) {
                const label = cells[0].textContent.trim();
                if (label === 'Chance of any rain') {
                    const chances = Array.from(cells).slice(1).map(c => c.textContent.trim()).filter(t => t !== '–');
                    if (chances.length > 0) {
                        result += "Chance of rain: " + chances.join(', ') + "\n";
                    }
                }
            }
        });
    }

    result += "\n";
    return result;
})();

